mapper.select:
SELECT NVL(COUNT(r.fk_memberid), 0) AS sent, NVL(SUM(CASE WHEN r.viewed_at IS NOT NULL THEN 1 ELSE 0 END), 0) AS viewed, NVL(SUM(CASE WHEN r.response_status = 1 THEN 1 ELSE 0 END), 0) AS accepted, NVL(SUM(CASE WHEN r.response_status = 2 THEN 1 ELSE 0 END), 0) AS rejected
FROM tbl_offer_letter ol LEFT JOIN tbl_offer_submit s ON s.fk_offer_letter_id = ol.offer_letter_id LEFT JOIN tbl_offer_response r ON r.fk_offer_submit_id = s.offer_submit_id JOIN tbl_job_posting jp ON jp.job_id = ol.fk_job_id
WHERE jp.fk_memberid = #{companyMemberId}

SELECT l.offer_letter_id AS offerLetterId, l.fk_job_id AS jobId, l.title AS title, l.message AS message,
( SELECT s.expire_at FROM tbl_offer_submit s WHERE s.fk_offer_letter_id = l.offer_letter_id ORDER BY s.send_at DESC FETCH FIRST 1 ROW ONLY ) AS expireAt
FROM tbl_offer_letter l WHERE l.offer_letter_id = #{id}

SELECT CASE WHEN EXISTS (
  SELECT 1
  FROM TBL_OFFER_SUBMIT s
  WHERE s.fk_offer_letter_id = #{offerLetterId}
) THEN 1 ELSE 0 END AS ok
FROM dual

SELECT CASE WHEN EXISTS (
  SELECT 1
  FROM TBL_OFFER_LETTER ol
  JOIN TBL_JOB_POSTING jp
    ON jp.JOB_ID = ol.FK_JOB_ID
  WHERE ol.OFFER_LETTER_ID = #{offerLetterId}
    AND jp.FK_MEMBERID = #{companyMemberId}
) THEN 1 ELSE 0 END AS ok
FROM dual
